import{_ as a,c as e,o as i,aj as s,a_ as d,a$ as l,b0 as r,b1 as p}from"./chunks/framework.CoirRWyn.js";const m=JSON.parse('{"title":"2.3 AI桌面应用 [AI desktop apps]","description":"","frontmatter":{},"headers":[],"relativePath":"module_2/2.3AI桌面应用[AI desktop apps].md","filePath":"module_2/2.3AI桌面应用[AI desktop apps].md"}'),h={name:"module_2/2.3AI桌面应用[AI desktop apps].md"};function o(n,t,c,k,b,_){return i(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="_2-3-ai桌面应用-ai-desktop-apps" tabindex="-1">2.3 AI桌面应用 [AI desktop apps] <a class="header-anchor" href="#_2-3-ai桌面应用-ai-desktop-apps" aria-label="Permalink to “2.3 AI桌面应用 [AI desktop apps]”">​</a></h1><blockquote><p><strong>主题：</strong> 使用桌面端 AI 应用读取文件、图片、网页或本地资料，减少来回复制，提高真实工作流效率。</p></blockquote><p>AI 桌面应用把模型能力和本地文件系统连接起来，可以读取、整理、移动、改写文件，也可以基于文件提出行动方案。它比普通聊天更接近一个工作助手，适合处理文件夹整理、资料归纳、报告草稿、项目检查等任务。</p><p><img src="'+d+'" alt="alt text"></p><p>普通聊天主要依赖用户复制粘贴内容。桌面应用则可以在授权范围内接触本地文件、项目资料和工作文件夹，因此更适合处理真实文件工作流，例如整理旅游资料、归档文件、检查材料和生成计划。</p><p><img src="'+l+'" alt="alt text"></p><p>桌面应用通常可以结合模型知识、网页搜索、文件读取、文件写入、文件搜索和文件移动等能力。推荐流程是：用户提出任务，AI 先给行动计划，用户检查计划，确认后再执行。</p><p><img src="'+r+'" alt="alt text"></p><p>桌面应用不会一次性读取电脑里的所有内容，而是按任务需要读取相关文件。用户仍然需要说明任务目标、相关文件夹和重点材料。AI 读取越精准，结果越不容易被无关文件干扰。</p><p><img src="'+p+'" alt="alt text"></p><p>桌面应用涉及本地文件权限，因此要谨慎使用。尤其是删除、移动、重命名、写入文件等操作，最好先让 AI 生成计划，用户确认后再执行。</p><h2 id="桌面-ai-可以做什么" tabindex="-1">桌面 AI 可以做什么 <a class="header-anchor" href="#桌面-ai-可以做什么" aria-label="Permalink to “桌面 AI 可以做什么”">​</a></h2><ul><li>阅读多个文档并总结；</li><li>查找文件夹中重复或过期文件；</li><li>根据项目资料生成计划；</li><li>检查论文、报告、PPT 或代码文件；</li><li>批量整理命名不规范的文件；</li><li>根据本地材料生成下一步行动清单。</li></ul><h2 id="使用桌面-ai-的原则" tabindex="-1">使用桌面 AI 的原则 <a class="header-anchor" href="#使用桌面-ai-的原则" aria-label="Permalink to “使用桌面 AI 的原则”">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>含义</th><th>目的</th></tr></thead><tbody><tr><td>最小权限</td><td>只让 AI 接触任务相关文件夹</td><td>降低隐私和误操作风险</td></tr><tr><td>先计划</td><td>修改前先让 AI 说明操作步骤</td><td>方便用户检查</td></tr><tr><td>再确认</td><td>用户确认后再执行写入、移动或删除</td><td>防止错误修改</td></tr><tr><td>可回退</td><td>重要文件先备份</td><td>避免不可逆损失</td></tr><tr><td>分阶段</td><td>大任务拆成读取、分析、修改、检查</td><td>提高稳定性</td></tr></tbody></table><h2 id="可直接套用的-prompt-模板" tabindex="-1">可直接套用的 Prompt 模板 <a class="header-anchor" href="#可直接套用的-prompt-模板" aria-label="Permalink to “可直接套用的 Prompt 模板”">​</a></h2><h3 id="模板-1-读取文件但不修改" tabindex="-1">模板 1：读取文件但不修改 <a class="header-anchor" href="#模板-1-读取文件但不修改" aria-label="Permalink to “模板 1：读取文件但不修改”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请读取【文件夹/文件名】中的资料，帮我总结主要内容。现在不要修改、删除或移动任何文件，只需要先列出你读取了哪些文件，并给出摘要。</span></span></code></pre></div><h3 id="模板-2-先计划再执行" tabindex="-1">模板 2：先计划再执行 <a class="header-anchor" href="#模板-2-先计划再执行" aria-label="Permalink to “模板 2：先计划再执行”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我想整理这个项目文件夹。请先扫描文件结构，找出重复文件、无关文件和需要归档的文件。请先输出整理计划，不要直接执行移动或删除操作。</span></span></code></pre></div><h3 id="模板-3-基于文件生成报告" tabindex="-1">模板 3：基于文件生成报告 <a class="header-anchor" href="#模板-3-基于文件生成报告" aria-label="Permalink to “模板 3：基于文件生成报告”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请基于这个文件夹中的文档和表格，生成一份项目进展报告。请说明你参考了哪些文件，提取了哪些关键信息，并把不确定内容单独列出来。</span></span></code></pre></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>AI 桌面应用适合处理真实文件工作流，但必须遵循“最小权限、先计划、再确认、后执行”的原则。它可以减少复制粘贴，提高资料整理效率，但用户仍然需要掌握最终判断权。</p><hr>',25)])])}const A=a(h,[["render",o]]);export{m as __pageData,A as default};
